"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";

export type CarFormData = {
  car_company: string;
  car_brand: string;
  car_registration_number: string;
  car_number: string;
  car_driver: string;
  car_phone: string;
  car_type: string;
  car_mile: string;
  car_registration_date: string;
};

type Option = { value: string; label: string };

type CarOptions = {
  companies: Option[];
  brands: Option[];
};

export default function CarForm({
  carId,
  onSaved,
}: {
  carId?: string | null;
  onSaved: () => void;
}) {
  const [options, setOptions] = useState<CarOptions>({ companies: [], brands: [] });
  const [form, setForm] = useState<CarFormData>({
    car_company: "",
    car_brand: "",
    car_registration_number: "",
    car_number: "",
    car_driver: "",
    car_phone: "",
    car_type: "",
    car_mile: "",
    car_registration_date: "",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    apiFetch<CarOptions>("/api/car/options").then((data) => setOptions(data));
  }, []);

  useEffect(() => {
    if (!carId) return;
    apiFetch<CarFormData>(`/api/cars/${carId}`).then((data) => setForm(data));
  }, [carId]);

  function onChange(e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  }

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      if (carId) {
        await apiFetch(`/api/cars/${carId}`, {
          method: "PUT",
          body: JSON.stringify(form),
        });
      } else {
        await apiFetch(`/api/cars`, {
          method: "POST",
          body: JSON.stringify(form),
        });
      }
      onSaved();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Save failed");
    } finally {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={onSubmit} className="space-y-4">
      <div className="grid gap-4 md:grid-cols-2">
        <div>
          <label className="text-sm font-semibold text-slate-600">บริษัท/สาขา</label>
          <select
            name="car_company"
            value={form.car_company}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          >
            <option value="">กรุณาเลือก...</option>
            {options.companies.map((opt, index) => (
              <option key={`${opt.value}-${opt.label}-${index}`} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
        </div>
        <div>
          <label className="text-sm font-semibold text-slate-600">ยี่ห้อรถ</label>
          <select
            name="car_brand"
            value={form.car_brand}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          >
            <option value="">กรุณาเลือก...</option>
            {options.brands.map((opt, index) => (
              <option key={`${opt.value}-${opt.label}-${index}`} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        <div>
          <label className="text-sm font-semibold text-slate-600">เลขทะเบียนรถ</label>
          <input
            name="car_registration_number"
            value={form.car_registration_number}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          />
        </div>
        <div>
          <label className="text-sm font-semibold text-slate-600">เลขประจำรถ</label>
          <input
            name="car_number"
            value={form.car_number}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          />
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        <div>
          <label className="text-sm font-semibold text-slate-600">พนักงานขับรถ</label>
          <input
            name="car_driver"
            value={form.car_driver}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          />
        </div>
        <div>
          <label className="text-sm font-semibold text-slate-600">เบอร์ติดต่อ</label>
          <input
            name="car_phone"
            value={form.car_phone}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          />
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <div>
          <label className="text-sm font-semibold text-slate-600">ประเภทรถ</label>
          <input
            name="car_type"
            value={form.car_type}
            onChange={onChange}
            placeholder="เช่น รถ 6 ล้อ"
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          />
        </div>
        <div>
          <label className="text-sm font-semibold text-slate-600">เลขไมล์</label>
          <input
            name="car_mile"
            value={form.car_mile}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          />
        </div>
        <div>
          <label className="text-sm font-semibold text-slate-600">วันที่จดทะเบียน</label>
          <input
            type="date"
            name="car_registration_date"
            value={form.car_registration_date}
            onChange={onChange}
            className="mt-2 w-full rounded-xl border border-blue-100 bg-white px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
            required
          />
        </div>
      </div>

      {error && (
        <div className="rounded-xl border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-600">
          {error}
        </div>
      )}

      <div className="flex justify-end gap-3 pt-2">
        <button
          type="submit"
          disabled={loading}
          className="rounded-xl bg-gradient-to-r from-blue-600 to-sky-500 px-4 py-2 text-sm font-semibold text-white shadow-lg shadow-blue-200"
        >
          {loading ? "Saving..." : "Save"}
        </button>
      </div>
    </form>
  );
}
